            cur['relation_lines'].append(val)
            low=val.lower()
            if low.startswith('replaced-by'):
                ids=re.findall(r'ADR-\d+', val)
                if ids: cur['replaced_by_id']=ids[0]
            elif low.startswith('replaces'):
                cur['replaces_ids'].extend(re.findall(r'ADR-\d+', val))
    if cur: blocks.append(cur)
