    ids=[b['id'] for b in blocks]
    counts={x:ids.count(x) for x in set(ids)}
    dups=[x for x,c in counts.items() if c>1]
    if dups: out.append('duplicate id(s): '+', '.join(sorted(dups)))
    if dups:
