        if b['replaced_by_id']:
            t=b['replaced_by_id']
            if t==b['id']: out.append(f'{b["id"]} self-reference in replaced_by_id')
            if t not in idset: out.append(f'{b["id"]} replaced_by missing target {t}')
    # reciprocal mismatches only if ids unique enough
    by={b['id']:b for b in blocks}
