                out.append(f'status mismatch: {b["id"]} has replaced_by_id but governance_state={b["governance_state"]}')
            if b['governance_state']==CONF and b['replaced_by_id']:
                out.append(f'status mismatch: {b["id"]} is active/confirmed but replaced_by_id={b["replaced_by_id"]}')
