                out.append(f'PLAN references missing active decision {r}')
            elif by[r]['governance_state'] != CONF:
                out.append(f'PLAN references non-active decision {r} state={by[r]["governance_state"]}')
        for a in active_ids(blocks):
            # If plan has an explicit Related active decisions list, it should match all active IDs.
            if plan_refs and a not in plan_refs:
                out.append(f'PLAN omits active decision {a}')
    return out

