def adr_blocks(txt):
    lines=txt.splitlines(); blocks={}; cur=None; buf=[]
    for line in lines:
        m=re.match(r'^(##\s+(ADR-\d+):.*)$', line)
        if m:
            if cur: blocks[cur]='\n'.join(buf).strip()
            cur=m.group(2); buf=[line]
        elif cur:
            if line.startswith('## '):
                blocks[cur]='\n'.join(buf).strip(); cur=None; buf=[]
            else: buf.append(line)
    if cur: blocks[cur]='\n'.join(buf).strip()
    return blocks
