    blocks=adr_blocks((root/scen/'docs'/'DECISIONS.md').read_text(encoding='utf-8'))
    print(f'### {scen} referenced ADR bodies')
    for r in refs:
        print(f'--- {r} ---')
        print(blocks.get(r,'<missing>'))
    print()
